import ScopedPageContent from '../components/ScopedPageContent';

const pageCss = ":root{\n    --bg:           #F8F9FA;\n    --bg-alt:       #FAFAF8;\n    --bg-soft:      #F1F2F4;\n    --bg-dark:      #0E1116;\n    --heading:      #2D3748;\n    --body:         #4A5568;\n    --muted:        #718096;\n    --accent-soft:  #8FBC8F;\n    --line:         #B38B6D;\n    --line-soft:    rgba(179, 139, 109, .28);\n    --line-faint:   rgba(45, 55, 72, .08);\n    --line-strong:  rgba(45, 55, 72, .80);\n    --cta:          #576DB5;\n    --cta-hover:    #46599C;\n    --link:         #1E3A8A;\n    --warm:         #E5A674;\n    --font: 'Plus Jakarta Sans', system-ui, -apple-system, Segoe UI, sans-serif;\n    --max: 1320px;\n    --gutter: 24px;\n    --pad: clamp(20px, 4vw, 48px);\n  }\n\n  *{ box-sizing:border-box; }\n  html,body{ margin:0; padding:0; }\n  body{\n    background:var(--bg);\n    color:var(--body);\n    font-family:var(--font);\n    font-size:16px; line-height:1.6;\n    -webkit-font-smoothing:antialiased;\n    text-rendering:optimizeLegibility;\n    overflow-x:hidden;\n    scroll-behavior: smooth;\n  }\n  a{ color:inherit; text-decoration:none; }\n  button{ font-family:inherit; cursor:pointer; border:0; background:transparent; }\n  img{ max-width:100%; display:block; }\n\n  .container{\n    max-width:var(--max);\n    margin:0 auto;\n    padding-left:var(--pad);\n    padding-right:var(--pad);\n    position:relative;\n  }\n\n  /* ============ NAV ============ */\n  .nav-wrap{\n    position:sticky; top:0; z-index:50;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    background: rgba(248, 249, 250, .82);\n    border-bottom: 1px solid var(--line-soft);\n  }\n  .nav{\n    display:grid; grid-template-columns: auto 1fr auto;\n    align-items:center; height:78px; gap:32px;\n  }\n  .logo{ display:flex; align-items:center; height:40px; font-weight:800; font-size:18px; color:var(--heading); letter-spacing:-.01em; }\n  .logo-mark{\n    width:34px; height:34px; border-radius:9px;\n    background: linear-gradient(135deg, var(--cta) 0%, #6E84C8 100%);\n    display:grid; place-items:center; margin-right:10px;\n    box-shadow: 0 6px 16px -8px rgba(87,109,181,.5);\n  }\n  .logo-mark svg{ color:#fff; }\n  .menu{ display:flex; justify-content:center; gap:6px; }\n  .menu a, .menu button.menu-link{\n    position:relative;\n    display:inline-flex; align-items:center; gap:6px;\n    padding:10px 14px;\n    font-size:14.5px; font-weight:500;\n    color:var(--body); border-radius:8px;\n    transition: color .2s ease, background .2s ease;\n  }\n  .menu a:hover, .menu button.menu-link:hover{ color:var(--heading); background: rgba(179,139,109,.06); }\n  .menu a::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(0); transform-origin:left;\n    transition: transform .25s ease;\n  }\n  .menu a:hover::after{ transform:scaleX(1); }\n  .menu .menu-link.active{ color:var(--heading); background: rgba(179,139,109,.08); }\n  .menu .menu-link.active::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(1);\n  }\n  .menu .chev{ width:12px; height:12px; color:var(--muted); }\n  .nav-right{ display:flex; align-items:center; gap:8px; }\n  .lang{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 9px 12px; font-size:13.5px; font-weight:600;\n    color:var(--body); border:1px solid var(--line-soft);\n    border-radius: 999px; background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .lang:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n  .lang .globe{ color:var(--line); }\n  .lang .chev{ color:var(--muted); }\n  .icon-btn{\n    width:40px; height:40px; display:grid; place-items:center;\n    border-radius:50%; border:1px solid var(--line-soft);\n    color:var(--body); background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .icon-btn:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n\n  /* ============ PAGE HEAD ============ */\n  .page-head{\n    padding: clamp(28px, 3.5vw, 48px) 0 clamp(24px, 3vw, 36px);\n    border-bottom: 1.5px solid var(--line-strong);\n  }\n  .ph-row{\n    display: grid;\n    grid-template-columns: 1.5fr 1fr;\n    gap: clamp(24px, 4vw, 48px);\n    align-items: center;\n  }\n  .ph-eyebrow{\n    display: flex; align-items: center; gap: 12px;\n    font-size: 10.5px; font-weight: 700;\n    letter-spacing: .22em; text-transform: uppercase;\n    color: var(--muted); margin-bottom: 14px;\n  }\n  .ph-eyebrow::before{\n    content: \"\"; width: 6px; height: 6px; background: var(--line); flex-shrink: 0;\n  }\n  .ph-eyebrow .ph-issue{\n    margin-left: auto; color: var(--heading); font-weight: 700;\n  }\n  .ph-title{\n    font-size: clamp(34px, 4.4vw, 60px);\n    font-weight: 700; color: var(--heading);\n    line-height: 1.02; letter-spacing: -.028em;\n    margin: 0; text-wrap: balance;\n  }\n  .ph-meta{ text-align: right; }\n  .ph-meta-row{\n    display: flex; justify-content: flex-end;\n    align-items: baseline; gap: 14px;\n    border-bottom: 1px solid var(--line-faint);\n    padding: 7px 0;\n    font-size: 12px; font-weight: 500;\n    color: var(--body); letter-spacing: .01em;\n  }\n  .ph-meta-row:first-child{ border-top: 1px solid var(--line-faint); }\n  .ph-meta-row strong{\n    font-size: 10px; font-weight: 700;\n    color: var(--muted); letter-spacing: .14em; text-transform: uppercase;\n  }\n\n  /* ============ FAQ LAYOUT ============ */\n  .faq-section{\n    padding: clamp(40px, 5vw, 72px) 0 clamp(72px, 9vw, 120px);\n    border-bottom: 1.5px solid var(--line-strong);\n  }\n\n  /* Search bar */\n  .faq-search{\n    display: flex; align-items: center; gap: 12px;\n    padding: 16px 20px;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid rgba(255,255,255,.9);\n    box-shadow: 0 1px 0 rgba(255,255,255,.95) inset, 0 8px 24px -16px rgba(45,55,72,.16);\n    border-radius: 999px;\n    margin-bottom: clamp(40px, 5vw, 64px);\n    max-width: 720px;\n  }\n  .faq-search svg{ width: 18px; height: 18px; color: var(--muted); flex-shrink: 0; }\n  .faq-search input{\n    flex: 1; min-width: 0;\n    border: 0; background: transparent;\n    font-family: var(--font);\n    font-size: 15px; font-weight: 500;\n    color: var(--heading);\n    outline: none;\n  }\n  .faq-search input::placeholder{ color: var(--muted); }\n  .faq-search-clear{\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .12em; text-transform: uppercase;\n    color: var(--muted);\n    padding: 4px 10px;\n    border: 1px solid var(--line-faint);\n    border-radius: 999px;\n    transition: color .2s, border-color .2s;\n    display: none;\n  }\n  .faq-search-clear.is-visible{ display: inline-flex; }\n  .faq-search-clear:hover{ color: var(--heading); border-color: var(--line); }\n\n  .faq-grid{\n    display: grid;\n    grid-template-columns: 240px 1fr;\n    gap: clamp(40px, 5vw, 80px);\n    align-items: start;\n  }\n\n  /* Sidebar nav (sticky on desktop) */\n  .faq-nav{\n    position: sticky;\n    top: 100px;\n  }\n  .faq-nav-h{\n    font-size: 11px; font-weight: 800;\n    color: var(--muted);\n    letter-spacing: .22em; text-transform: uppercase;\n    margin: 0 0 18px;\n    padding-bottom: 14px;\n    border-bottom: 1.5px solid var(--heading);\n  }\n  .faq-nav-list{\n    list-style: none;\n    margin: 0; padding: 0;\n  }\n  .faq-nav-list li{\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .faq-nav-link{\n    display: flex; align-items: baseline; justify-content: space-between;\n    gap: 12px;\n    padding: 14px 0;\n    color: var(--body);\n    font-size: 14px; font-weight: 600;\n    letter-spacing: -.005em;\n    transition: color .2s, padding-left .25s ease;\n  }\n  .faq-nav-link:hover{ color: var(--heading); padding-left: 6px; }\n  .faq-nav-link.is-active{\n    color: var(--heading);\n    padding-left: 6px;\n    position: relative;\n  }\n  .faq-nav-link.is-active::before{\n    content: \"\";\n    position: absolute;\n    left: -12px; top: 50%;\n    transform: translateY(-50%);\n    width: 6px; height: 6px;\n    background: var(--line);\n    border-radius: 50%;\n  }\n  .faq-nav-num{\n    font-size: 11px;\n    font-weight: 700;\n    color: var(--muted);\n    letter-spacing: .08em;\n    flex-shrink: 0;\n  }\n\n  /* Right column */\n  .faq-content{\n    min-width: 0;\n  }\n  .faq-cat{\n    margin-bottom: clamp(56px, 7vw, 88px);\n  }\n  .faq-cat:last-child{ margin-bottom: 0; }\n\n  .faq-cat-head{\n    display: flex; align-items: baseline; gap: 18px;\n    padding-bottom: 16px;\n    border-bottom: 1.5px solid var(--heading);\n    margin-bottom: 8px;\n  }\n  .faq-cat-num{\n    font-size: clamp(16px, 1.8vw, 22px);\n    font-weight: 800;\n    color: var(--heading);\n    letter-spacing: -.02em;\n    line-height: 1;\n  }\n  .faq-cat-title{\n    font-size: clamp(22px, 2.6vw, 32px);\n    font-weight: 700;\n    color: var(--heading);\n    line-height: 1.05;\n    letter-spacing: -.025em;\n    margin: 0;\n  }\n  .faq-cat-count{\n    margin-left: auto;\n    font-size: 11px;\n    font-weight: 700;\n    color: var(--muted);\n    letter-spacing: .14em; text-transform: uppercase;\n  }\n\n  /* Q&A item */\n  .faq-item{\n    border-bottom: 1px solid var(--line-faint);\n    transition: padding-left .3s ease;\n  }\n  .faq-item.is-hidden{ display: none; }\n  .faq-item:hover{ padding-left: 4px; }\n  .faq-item.is-open{\n    padding-left: 4px;\n  }\n\n  .faq-q{\n    width: 100%;\n    text-align: left;\n    background: transparent;\n    border: 0;\n    padding: 22px 0;\n    display: grid;\n    grid-template-columns: 56px 1fr 36px;\n    gap: 18px;\n    align-items: baseline;\n    cursor: pointer;\n    color: var(--heading);\n    font-family: var(--font);\n  }\n  .faq-q-num{\n    font-size: 12px;\n    font-weight: 700;\n    color: var(--muted);\n    letter-spacing: .08em;\n    line-height: 1.4;\n  }\n  .faq-q-text{\n    font-size: clamp(15.5px, 1.4vw, 18px);\n    font-weight: 700;\n    color: var(--heading);\n    line-height: 1.35;\n    letter-spacing: -.01em;\n    transition: color .25s;\n  }\n  .faq-item:hover .faq-q-text{ color: var(--cta); }\n  .faq-item.is-open .faq-q-text{ color: var(--cta); }\n\n  .faq-q-icon{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    border: 1px solid var(--line-soft);\n    color: var(--heading);\n    display: grid; place-items: center;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), background .25s, color .25s, border-color .25s;\n    align-self: center;\n    justify-self: end;\n    flex-shrink: 0;\n  }\n  .faq-q-icon svg{ width: 14px; height: 14px; transition: transform .35s; }\n  .faq-item:hover .faq-q-icon{ border-color: var(--line); color: var(--cta); }\n  .faq-item.is-open .faq-q-icon{\n    background: var(--heading);\n    color: #fff;\n    border-color: var(--heading);\n    transform: rotate(45deg);\n  }\n\n  .faq-a{\n    overflow: hidden;\n    max-height: 0;\n    opacity: 0;\n    transition: max-height .45s cubic-bezier(.2,.7,.2,1), opacity .35s ease, padding .35s ease;\n  }\n  .faq-item.is-open .faq-a{\n    max-height: 600px;\n    opacity: 1;\n    padding-bottom: 24px;\n  }\n  .faq-a-inner{\n    padding-left: 74px;\n    max-width: 64ch;\n  }\n  .faq-a-inner p{\n    margin: 0 0 12px;\n    font-size: 14.5px;\n    line-height: 1.7;\n    color: var(--body);\n  }\n  .faq-a-inner p:last-child{ margin-bottom: 0; }\n  .faq-a-inner ul{\n    margin: 8px 0 12px;\n    padding: 0;\n    list-style: none;\n  }\n  .faq-a-inner li{\n    position: relative;\n    padding-left: 16px;\n    font-size: 14.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin-bottom: 6px;\n  }\n  .faq-a-inner li::before{\n    content: \"\";\n    position: absolute;\n    left: 0; top: 12px;\n    width: 6px; height: 1px;\n    background: var(--line);\n  }\n  .faq-a-inner a{\n    color: var(--cta);\n    border-bottom: 1px solid currentColor;\n    font-weight: 600;\n  }\n  .faq-a-inner a:hover{ color: var(--cta-hover); }\n\n  /* Empty state when search has no matches */\n  .faq-empty{\n    display: none;\n    padding: 48px 0;\n    text-align: center;\n    color: var(--muted);\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .faq-empty.is-visible{ display: block; }\n  .faq-empty strong{\n    display: block;\n    color: var(--heading);\n    font-size: 18px;\n    font-weight: 700;\n    margin-bottom: 6px;\n  }\n\n  /* ============ FEATURES (SS1 inspired) ============ */\n  .why-us{\n    padding: clamp(72px, 9vw, 120px) 0;\n    background: var(--bg);\n    border-top: 1px solid var(--line-faint);\n  }\n\n  .wu-head{\n    text-align: center;\n    max-width: 640px;\n    margin: 0 auto clamp(40px, 5vw, 64px);\n  }\n  .wu-eyebrow{\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .22em; text-transform: uppercase;\n    color: var(--line);\n    margin-bottom: 16px;\n  }\n  .wu-eyebrow::before,\n  .wu-eyebrow::after{\n    content: \"\"; width: 24px; height: 1px;\n    background: var(--line);\n  }\n  .wu-title{\n    font-size: clamp(28px, 3.4vw, 42px);\n    font-weight: 700;\n    color: var(--heading);\n    line-height: 1.05;\n    letter-spacing: -.025em;\n    margin: 0 0 12px;\n    text-wrap: balance;\n  }\n  .wu-sub{\n    font-size: 15px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0 auto;\n    max-width: 52ch;\n  }\n\n  /* 2x2 grid: alternating image / text cards */\n  .wu-grid{\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 20px;\n  }\n\n  /* Shared base */\n  .wu-card{\n    border-radius: 20px;\n    border: 1px solid var(--line-soft);\n    overflow: hidden;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), box-shadow .35s ease, border-color .35s ease;\n    position: relative;\n  }\n\n  /* Image-style card (cream w/ mockup) */\n  .wu-card-img{\n    background:\n      radial-gradient(120% 100% at 50% 0%, rgba(143,188,143,.10), transparent 60%),\n      var(--bg-soft);\n    padding: 40px 36px;\n    display: grid; place-items: center;\n    min-height: 280px;\n  }\n  .wu-card-img:hover{\n    transform: translateY(-4px);\n    border-color: var(--line);\n    box-shadow: 0 24px 48px -28px rgba(45,55,72,.20);\n  }\n\n  /* Text-style card (white glass) */\n  .wu-card-text{\n    background: rgba(255,255,255,.7);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border-color: rgba(255,255,255,.9);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.95) inset,\n      0 12px 28px -20px rgba(45,55,72,.14);\n    padding: 36px 36px 32px;\n    display: flex; flex-direction: column;\n    text-decoration: none;\n    color: var(--heading);\n    isolation: isolate;\n    min-height: 280px;\n  }\n  .wu-card-text::after{\n    content: \"\"; position: absolute;\n    top: 0; left: 0; right: 0; height: 2px;\n    background: linear-gradient(90deg, var(--cta), var(--accent-soft), var(--line));\n    transform: scaleX(0); transform-origin: left;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1);\n  }\n  .wu-card-text:hover{\n    transform: translateY(-4px);\n    background: rgba(255,255,255,.95);\n    border-color: rgba(255,255,255,1);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,1) inset,\n      0 24px 52px -28px rgba(45,55,72,.22),\n      0 10px 22px -14px rgba(87,109,181,.18);\n  }\n  .wu-card-text:hover::after{ transform: scaleX(1); }\n\n  .wu-tag{\n    display: inline-flex; align-items: center; gap: 8px;\n    align-self: flex-start;\n    padding: 5px 12px 5px 5px;\n    background: rgba(143,188,143,.18);\n    border: 1px solid rgba(143,188,143,.4);\n    border-radius: 999px;\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .12em; text-transform: uppercase;\n    color: #5a7d5a;\n    margin-bottom: 18px;\n    transition: background .25s, border-color .25s;\n  }\n  .wu-tag::before{\n    content: \"\";\n    width: 16px; height: 16px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .wu-card-text:hover .wu-tag{\n    background: rgba(143,188,143,.25);\n    border-color: rgba(143,188,143,.6);\n  }\n\n  .wu-card-title{\n    font-size: clamp(20px, 2vw, 26px);\n    font-weight: 700;\n    color: var(--heading);\n    line-height: 1.2;\n    letter-spacing: -.018em;\n    margin: 0 0 12px;\n    text-wrap: balance;\n    transition: color .25s;\n  }\n  .wu-card-text:hover .wu-card-title{ color: var(--cta); }\n  .wu-card-desc{\n    font-size: 14px;\n    line-height: 1.6;\n    color: var(--body);\n    margin: 0 0 22px;\n    flex-grow: 1;\n  }\n\n  .wu-btn{\n    align-self: flex-start;\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 10px 18px;\n    background: var(--accent-soft);\n    color: #fff;\n    border-radius: 999px;\n    font-size: 12.5px; font-weight: 700;\n    letter-spacing: .04em;\n    transition: background .25s, gap .2s, transform .15s, box-shadow .25s;\n  }\n  .wu-btn:hover{\n    background: var(--cta);\n    gap: 12px;\n    transform: translateY(-1px);\n    box-shadow: 0 8px 18px -8px rgba(87,109,181,.5);\n  }\n  .wu-btn svg{ width: 12px; height: 12px; }\n\n  /* Mockup illustrations inside image cards */\n  .wu-mock{\n    width: 100%;\n    max-width: 320px;\n    position: relative;\n  }\n\n  /* Mockup 1 — dashboard card */\n  .wu-mock-dash{\n    background: #fff;\n    border: 1px solid var(--line-faint);\n    border-radius: 14px;\n    padding: 18px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.95) inset,\n      0 16px 36px -20px rgba(45,55,72,.18);\n  }\n  .wu-mock-row{\n    display: flex; align-items: center; gap: 10px;\n    padding: 10px 0;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .wu-mock-row:last-child{ border-bottom: 0; padding-bottom: 0; }\n  .wu-mock-row:first-child{ padding-top: 0; }\n  .wu-mock-avatar{\n    width: 34px; height: 34px; border-radius: 50%;\n    flex-shrink: 0;\n  }\n  .wu-mock-avatar.a1{ background: linear-gradient(135deg, var(--warm), var(--line)); }\n  .wu-mock-avatar.a2{ background: linear-gradient(135deg, var(--accent-soft), var(--cta)); }\n  .wu-mock-text{ flex: 1; min-width: 0; }\n  .wu-mock-name{\n    font-size: 13px; font-weight: 700;\n    color: var(--heading);\n    line-height: 1.2;\n  }\n  .wu-mock-sub{\n    font-size: 11px; color: var(--muted);\n    margin-top: 2px;\n  }\n  .wu-mock-amt{\n    font-size: 13px; font-weight: 700;\n    color: var(--heading);\n  }\n  .wu-mock-amt.green{ color: #5a7d5a; }\n  .wu-mock-pill{\n    margin-top: 14px;\n    align-self: center;\n    background: var(--accent-soft);\n    color: #fff;\n    padding: 8px 16px;\n    border-radius: 999px;\n    font-size: 11.5px; font-weight: 700;\n    text-align: center;\n    width: fit-content;\n    margin-left: auto; margin-right: auto;\n    display: block;\n  }\n\n  /* Mockup 2 — finance health */\n  .wu-mock-health{\n    background: #fff;\n    border: 1px solid var(--line-faint);\n    border-radius: 14px;\n    padding: 22px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.95) inset,\n      0 16px 36px -20px rgba(45,55,72,.18);\n  }\n  .wu-mock-banner{\n    display: inline-flex; align-items: center; gap: 8px;\n    background: var(--accent-soft);\n    color: #fff;\n    padding: 6px 14px;\n    border-radius: 999px;\n    font-size: 11.5px; font-weight: 700;\n    margin-bottom: 18px;\n  }\n  .wu-mock-banner svg{ width: 12px; height: 12px; }\n  .wu-mock-row.headline{\n    border-bottom: 0;\n    padding: 0 0 14px;\n  }\n  .wu-mock-icon{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.2);\n    display: grid; place-items: center;\n    color: var(--accent-soft);\n    flex-shrink: 0;\n  }\n  .wu-mock-icon svg{ width: 16px; height: 16px; }\n  .wu-mock-bignum{\n    font-size: 38px; font-weight: 800;\n    color: var(--heading);\n    letter-spacing: -.03em;\n    line-height: 1;\n    margin-top: 14px;\n  }\n  .wu-mock-caption{\n    font-size: 12px; color: var(--muted);\n    margin-top: 6px;\n  }\n\n  /* ============ FOOTER ============ */\n  .footer{\n    background: var(--bg-alt);\n    color: var(--body);\n    padding: clamp(60px, 8vw, 90px) 0 32px;\n  }\n  .ft-grid{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr 1fr 1.4fr;\n    gap: clamp(28px, 4vw, 52px);\n    margin-bottom: 56px;\n  }\n  .ft-brand .ft-logo{\n    display:flex; align-items:center; height:38px; margin-bottom:18px;\n    font-size:18px; font-weight:800; color:var(--heading); letter-spacing:-.01em;\n  }\n  .ft-brand .ft-logo .logo-mark{ margin-right:10px; }\n  .ft-desc{ font-size:14px; line-height:1.65; color:var(--body); max-width: 32ch; margin: 0 0 22px; }\n  .ft-social{ display:flex; gap:10px; }\n  .ft-social a{\n    width:36px; height:36px; border-radius:50%;\n    background: #fff; border:1px solid var(--line-soft);\n    display:grid; place-items:center; color: var(--body);\n    transition: color .2s, border-color .2s, transform .15s;\n  }\n  .ft-social a:hover{ color: var(--heading); border-color: var(--line); transform: translateY(-1px); }\n  .ft-h{\n    font-size: 12px; font-weight: 700; color: var(--heading);\n    letter-spacing: .12em; text-transform: uppercase;\n    margin: 0 0 18px;\n  }\n  .ft-list{ list-style:none; padding:0; margin:0; }\n  .ft-list li{ margin-bottom: 10px; }\n  .ft-list a{ font-size: 14px; color: var(--body); transition: color .2s; }\n  .ft-list a:hover{ color: var(--heading); }\n  .ft-text-link{ line-height: 1.5; }\n  .ft-news{ margin-top: 24px; }\n  .ft-news-h{ font-size: 13px; font-weight: 700; color: var(--heading); margin: 0 0 4px; }\n  .ft-news-p{ font-size: 13px; color: var(--muted); margin: 0 0 14px; line-height: 1.5; }\n  .ft-form{\n    display:flex; border: 1px solid var(--line-soft);\n    border-radius: 10px; overflow: hidden; background: #fff;\n  }\n  .ft-form input{\n    flex: 1; min-width: 0; padding: 11px 14px;\n    border: 0; font-family: var(--font); font-size: 13.5px;\n    color: var(--heading); background: transparent; outline: none;\n  }\n  .ft-form button{\n    background: var(--cta); color: #fff; padding: 0 16px;\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 13px; font-weight: 600; transition: background .2s;\n  }\n  .ft-form button:hover{ background: var(--cta-hover); }\n  .ft-bottom{\n    border-top: 1px solid var(--line-faint);\n    padding-top: 24px;\n    display:flex; align-items:center; justify-content:space-between;\n    flex-wrap: wrap; gap: 16px;\n  }\n  .ft-bottom span{ font-size: 13px; color: var(--muted); }\n  .ft-bottom-links{ display:flex; gap: 22px; flex-wrap: wrap; }\n  .ft-bottom-links a{ font-size: 13px; color: var(--muted); transition: color .2s; }\n  .ft-bottom-links a:hover{ color: var(--heading); }\n\n  /* ============ RESPONSIVE ============ */\n  @media (max-width: 1024px){\n    .menu, .nav-right .lang{ display:none; }\n    .ph-row{ grid-template-columns: 1fr; gap: 24px; }\n    .ph-meta{ text-align: left; }\n    .ph-meta-row{ justify-content: flex-start; }\n    .faq-grid{ grid-template-columns: 1fr; gap: 32px; }\n    .faq-nav{ position: static; }\n    .faq-nav-list{ display: flex; flex-wrap: wrap; gap: 0 6px; }\n    .faq-nav-list li{ border: 0; }\n    .faq-nav-link{ padding: 8px 14px; border: 1px solid var(--line-soft); border-radius: 999px; }\n    .faq-nav-link:hover, .faq-nav-link.is-active{ padding-left: 14px; }\n    .faq-nav-link.is-active{ background: var(--heading); color: #fff; border-color: var(--heading); }\n    .faq-nav-link.is-active::before{ display: none; }\n    .ctab-grid{ grid-template-columns: 1fr; gap: 24px; align-items: start; }\n    .wu-grid{ grid-template-columns: 1fr; gap: 16px; }\n    .wu-card-img{ min-height: 220px; padding: 32px 28px; }\n    .wu-card-text{ min-height: 0; padding: 28px; }\n    .ft-grid{ grid-template-columns: 1fr 1fr; }\n    .ft-brand{ grid-column: 1 / -1; }\n  }\n  @media (max-width: 640px){\n    .faq-q{ grid-template-columns: 44px 1fr 32px; gap: 12px; }\n    .faq-a-inner{ padding-left: 56px; }\n    .wu-cards{ grid-template-columns: 1fr; }\n    .wu-card-img{ padding: 28px 20px; min-height: 200px; }\n    .ft-grid{ grid-template-columns: 1fr; }\n    .ft-bottom{ flex-direction: column; align-items: flex-start; }\n  }";
const pageHtml = "<!-- ============ PAGE HEAD ============ -->\n  <section class=\"page-head\">\n    <div class=\"container\">\n      <div class=\"ph-row\">\n        <div>\n          <div class=\"ph-eyebrow\">\n            <span>Resources / FAQ</span>\n            <span class=\"ph-issue\">38 questions, 5 sections</span>\n          </div>\n          <h1 class=\"ph-title\">Questions, Answered.</h1>\n        </div>\n        <div class=\"ph-meta\">\n          <div class=\"ph-meta-row\"><strong>Sections</strong><span>Getting Started · Pricing · Services · Compliance · Reporting</span></div>\n          <div class=\"ph-meta-row\"><strong>Updated</strong><span>May 2026</span></div>\n          <div class=\"ph-meta-row\"><strong>Avg. response</strong><span>Under 4 hours</span></div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ============ FAQ SECTION ============ -->\n  <section class=\"faq-section\">\n    <div class=\"container\">\n\n      <!-- Search -->\n      <div class=\"faq-search\" data-faq-search-wrap>\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><line x1=\"21\" y1=\"21\" x2=\"16.65\" y2=\"16.65\"/></svg>\n        <input type=\"search\" placeholder=\"Search questions — try &lsquo;HIPAA&rsquo;, &lsquo;pricing&rsquo;, &lsquo;EHR&rsquo;…\" data-faq-search />\n        <button class=\"faq-search-clear\" type=\"button\" data-faq-clear>Clear</button>\n      </div>\n\n      <div class=\"faq-grid\">\n\n        <!-- LEFT: sticky sidebar nav -->\n        <aside class=\"faq-nav\">\n          <h4 class=\"faq-nav-h\">Sections</h4>\n          <ul class=\"faq-nav-list\">\n            <li><a class=\"faq-nav-link is-active\" href=\"#cat-01\" data-faq-jump=\"cat-01\"><span>Getting Started</span><span class=\"faq-nav-num\">01</span></a></li>\n            <li><a class=\"faq-nav-link\" href=\"#cat-02\" data-faq-jump=\"cat-02\"><span>Pricing &amp; Engagement</span><span class=\"faq-nav-num\">02</span></a></li>\n            <li><a class=\"faq-nav-link\" href=\"#cat-03\" data-faq-jump=\"cat-03\"><span>Services</span><span class=\"faq-nav-num\">03</span></a></li>\n            <li><a class=\"faq-nav-link\" href=\"#cat-04\" data-faq-jump=\"cat-04\"><span>Compliance &amp; Privacy</span><span class=\"faq-nav-num\">04</span></a></li>\n            <li><a class=\"faq-nav-link\" href=\"#cat-05\" data-faq-jump=\"cat-05\"><span>Reporting &amp; Results</span><span class=\"faq-nav-num\">05</span></a></li>\n          </ul>\n        </aside>\n\n        <!-- RIGHT: content -->\n        <div class=\"faq-content\" data-faq-content>\n\n          <!-- ===== CATEGORY 01 — Getting Started ===== -->\n          <div class=\"faq-cat\" id=\"cat-01\" data-faq-cat>\n            <div class=\"faq-cat-head\">\n              <span class=\"faq-cat-num\">01</span>\n              <h2 class=\"faq-cat-title\">Getting Started</h2>\n              <span class=\"faq-cat-count\">8 Q's</span>\n            </div>\n\n            <div class=\"faq-item is-open\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">01.01</span>\n                <span class=\"faq-q-text\">How long does onboarding take from signed contract to first campaign live?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>For most clinics, you'll go from signed contract to first campaign live in <strong>10–14 business days</strong>. Week one is discovery (audit + interviews), week two is asset production and account setup, and we usually launch the first campaign by day 12.</p>\n                  <p>Practices with already-running ad accounts and a healthy GBP often get there faster — sometimes in as little as a week.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">01.02</span>\n                <span class=\"faq-q-text\">What do you need from me before we kick off?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>We'll send a structured onboarding questionnaire. The essentials we need from your side:</p>\n                  <ul>\n                    <li>Admin access to Google Business Profile, Google Ads, Meta Ads, and your website CMS</li>\n                    <li>One stakeholder for our weekly 30-minute check-in (clinical or operational lead)</li>\n                    <li>Brand assets — logo, colors, fonts — even if rough</li>\n                    <li>Last 12 months of performance data, where available</li>\n                  </ul>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">01.03</span>\n                <span class=\"faq-q-text\">Do you offer a free consultation before signing?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Yes. Every prospective partner gets a free <strong>30-minute strategy call</strong> plus a high-level audit of your current funnel. You'll walk away with three concrete recommendations whether you sign with us or not.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">01.04</span>\n                <span class=\"faq-q-text\">Which states and regions do you serve?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>We work with healthcare practices across all 50 US states. Our deepest local-SEO experience is in Texas, Florida, California, New York, Illinois, and Arizona, but our playbook adapts to any local market.</p>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <!-- ===== CATEGORY 02 — Pricing ===== -->\n          <div class=\"faq-cat\" id=\"cat-02\" data-faq-cat>\n            <div class=\"faq-cat-head\">\n              <span class=\"faq-cat-num\">02</span>\n              <h2 class=\"faq-cat-title\">Pricing &amp; Engagement</h2>\n              <span class=\"faq-cat-count\">8 Q's</span>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">02.01</span>\n                <span class=\"faq-q-text\">How much does a typical engagement cost?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Our retainers start at <strong>$2,500/month</strong> for solo practitioners on a single channel and scale up to <strong>$15K+/month</strong> for multi-location specialty groups running full-stack programs.</p>\n                  <p>Ad spend is separate and goes directly to the platforms. We never mark it up.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">02.02</span>\n                <span class=\"faq-q-text\">Are contracts month-to-month or fixed term?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>The standard agreement is a <strong>3-month minimum commitment</strong> followed by a rolling month-to-month cadence with 30-day notice on either side. SEO-only retainers default to 6 months because the channel needs that runway to show real signal.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">02.03</span>\n                <span class=\"faq-q-text\">What's included in the base retainer?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Strategy, execution, and reporting on the channels in your scope. That includes:</p>\n                  <ul>\n                    <li>Weekly 30-minute partner check-in</li>\n                    <li>Monthly performance report with attribution</li>\n                    <li>Live dashboard access (24/7)</li>\n                    <li>Creative production within agreed asset volume</li>\n                    <li>Up to two automation templates from our N8N library</li>\n                  </ul>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">02.04</span>\n                <span class=\"faq-q-text\">Are there setup or onboarding fees?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>For standard retainers, no. We absorb onboarding into the first month. Larger custom builds — full website rebuilds, multi-location SEO migrations — carry a separate scoped fee disclosed upfront.</p>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <!-- ===== CATEGORY 03 — Services ===== -->\n          <div class=\"faq-cat\" id=\"cat-03\" data-faq-cat>\n            <div class=\"faq-cat-head\">\n              <span class=\"faq-cat-num\">03</span>\n              <h2 class=\"faq-cat-title\">Services &amp; Capabilities</h2>\n              <span class=\"faq-cat-count\">7 Q's</span>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">03.01</span>\n                <span class=\"faq-q-text\">Which services do you provide in-house versus outsourced?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Everything is handled in-house: SEO, paid media, social, content, branding, web design, email automation, and analytics. We do not white-label other agencies.</p>\n                  <p>The only exception is video production, where we partner with two vetted local studios.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">03.02</span>\n                <span class=\"faq-q-text\">Do you handle creative and design too?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Yes. Every retainer includes design hours scaled to your channel mix — landing pages, ad creative, social graphics, email templates. We can also take on full brand identity, website redesigns, and print collateral as scoped projects.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">03.03</span>\n                <span class=\"faq-q-text\">Can your automations integrate with my existing EHR?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>If your EHR exposes a documented API or webhook layer — Athena, Epic via API, eClinicalWorks, DrChrono, AdvancedMD, NextGen, Kareo — yes. For systems without API access, we use form bridges and structured CSV imports as the fallback.</p>\n                  <p>Tell us which EHR you run on the discovery call and we'll confirm the exact integration path before signing.</p>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <!-- ===== CATEGORY 04 — Compliance ===== -->\n          <div class=\"faq-cat\" id=\"cat-04\" data-faq-cat>\n            <div class=\"faq-cat-head\">\n              <span class=\"faq-cat-num\">04</span>\n              <h2 class=\"faq-cat-title\">Compliance &amp; Privacy</h2>\n              <span class=\"faq-cat-count\">6 Q's</span>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">04.01</span>\n                <span class=\"faq-q-text\">Are you HIPAA-compliant, and do you sign Business Associate Agreements?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Yes. We operate as a HIPAA-aware Business Associate and execute a <strong>BAA</strong> at the start of every engagement that touches PHI. All staff complete annual HIPAA training, and access controls are role-based with audit logging.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">04.02</span>\n                <span class=\"faq-q-text\">How do you handle protected health information (PHI)?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>We minimize PHI exposure by default. Marketing systems are kept in non-PHI environments wherever possible. When PHI must flow — appointment confirmations, intake forms, recall messaging — it travels through encrypted channels into BAA-covered tools (Twilio Healthcare, HIPAA-aware Mailchimp, AWS HIPAA-eligible services).</p>\n                  <p>Our internal access is least-privilege. Only the team members directly working on your account see anything, and access is revoked the day a teammate rolls off.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">04.03</span>\n                <span class=\"faq-q-text\">What happens to my data if we end the engagement?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>You own everything. On exit we hand over the full asset library — accounts, creative files, dashboards, automation JSONs, content drafts — and purge our copies within 30 days unless you ask us to retain them. The BAA continues to govern any residual PHI.</p>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <!-- ===== CATEGORY 05 — Reporting ===== -->\n          <div class=\"faq-cat\" id=\"cat-05\" data-faq-cat>\n            <div class=\"faq-cat-head\">\n              <span class=\"faq-cat-num\">05</span>\n              <h2 class=\"faq-cat-title\">Reporting &amp; Results</h2>\n              <span class=\"faq-cat-count\">9 Q's</span>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">05.01</span>\n                <span class=\"faq-q-text\">How often will I see reporting?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>Three layers: <strong>live dashboards</strong> available 24/7, a <strong>weekly Loom video</strong> walking you through the moves we made and what they did, and a <strong>monthly written report</strong> covering attribution, ROAS, and the next 30-day plan.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">05.02</span>\n                <span class=\"faq-q-text\">Which KPIs do you track by default?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>For most clinics: cost-per-acquisition (CPA), patient lifetime value (LTV), booked appointments by source, no-show rate, return on ad spend (ROAS), and organic traffic by intent cluster. We tailor the dashboard to your clinical specialties and revenue model in week one.</p>\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-faq-item>\n              <button class=\"faq-q\" data-faq-toggle>\n                <span class=\"faq-q-num\">05.03</span>\n                <span class=\"faq-q-text\">What if results don't show up after a few months?</span>\n                <span class=\"faq-q-icon\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg></span>\n              </button>\n              <div class=\"faq-a\">\n                <div class=\"faq-a-inner\">\n                  <p>We define success milestones together in week one and review them every 30 days. If we miss two consecutive months on a critical milestone, we run a structured root-cause review at our cost — and either reset the plan, restructure the retainer, or end the engagement cleanly. We don't keep partners on a contract that isn't working.</p>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <!-- Empty state -->\n          <div class=\"faq-empty\" data-faq-empty>\n            <strong>No matches.</strong>\n            Try a broader keyword, or <a href=\"#cta-help\" style=\"color:var(--cta);font-weight:600;border-bottom:1px solid currentColor\">talk to us directly →</a>\n          </div>\n\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ============ FEATURES (SS1 inspired) ============ -->\n  <section class=\"why-us\" id=\"why-us\">\n    <div class=\"container\">\n\n      <div class=\"wu-head\">\n        <div class=\"wu-eyebrow\">Built for clinics</div>\n        <h2 class=\"wu-title\">Tools built to simplify and empower your practice.</h2>\n        <p class=\"wu-sub\">Two systems that turn the loose ends of clinic marketing into a clean, compliant, measurable workflow.</p>\n      </div>\n\n      <div class=\"wu-grid\">\n\n        <!-- TL: Image card — referrals mockup -->\n        <div class=\"wu-card wu-card-img\">\n          <div class=\"wu-mock\">\n            <div class=\"wu-mock-dash\">\n              <div class=\"wu-mock-row\">\n                <div class=\"wu-mock-avatar a1\"></div>\n                <div class=\"wu-mock-text\">\n                  <div class=\"wu-mock-name\">Bilash R.</div>\n                  <div class=\"wu-mock-sub\">New patient</div>\n                </div>\n                <div class=\"wu-mock-amt\">+$23.46</div>\n              </div>\n              <span class=\"wu-mock-pill\">Booked</span>\n              <div class=\"wu-mock-row\">\n                <div class=\"wu-mock-avatar a2\"></div>\n                <div class=\"wu-mock-text\">\n                  <div class=\"wu-mock-name\">Bishwajit A.</div>\n                  <div class=\"wu-mock-sub\">Returning</div>\n                </div>\n                <div class=\"wu-mock-amt green\">+$25.45</div>\n              </div>\n              <span class=\"wu-mock-pill\" style=\"background:var(--cta)\">Confirmed</span>\n            </div>\n          </div>\n        </div>\n\n        <!-- TR: Text card -->\n        <a class=\"wu-card wu-card-text\" href=\"#feature-1\">\n          <span class=\"wu-tag\">Patient flow</span>\n          <h3 class=\"wu-card-title\">Send appointment confirmations the moment a patient books.</h3>\n          <p class=\"wu-card-desc\">Our intake automation turns form submissions into EHR records and confirmation messages in under three seconds — no front desk lift, no PHI leakage.</p>\n          <span class=\"wu-btn\">\n            Learn more\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/><polyline points=\"12 5 19 12 12 19\"/></svg>\n          </span>\n        </a>\n\n        <!-- BL: Text card -->\n        <a class=\"wu-card wu-card-text\" href=\"#feature-2\">\n          <span class=\"wu-tag\">Practice metrics</span>\n          <h3 class=\"wu-card-title\">Keep your numbers in check with one live dashboard.</h3>\n          <p class=\"wu-card-desc\">CPA, ROAS, no-show rate, and patient lifetime value — refreshed every fifteen minutes from your ad accounts, EHR, and analytics. One screen, no spreadsheets.</p>\n          <span class=\"wu-btn\">\n            Learn more\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/><polyline points=\"12 5 19 12 12 19\"/></svg>\n          </span>\n        </a>\n\n        <!-- BR: Image card — finance health mockup -->\n        <div class=\"wu-card wu-card-img\">\n          <div class=\"wu-mock\">\n            <div class=\"wu-mock-health\">\n              <div class=\"wu-mock-banner\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"20 6 9 17 4 12\"/></svg>\n                You earned $5,872.00\n              </div>\n              <div class=\"wu-mock-row headline\">\n                <div class=\"wu-mock-icon\">\n                  <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z\"/></svg>\n                </div>\n                <div class=\"wu-mock-text\">\n                  <div class=\"wu-mock-name\">Practice Health</div>\n                  <div class=\"wu-mock-sub\">Recent update</div>\n                </div>\n              </div>\n              <div class=\"wu-mock-bignum\">90%</div>\n              <div class=\"wu-mock-caption\">Your practice is performing above benchmark.</div>\n            </div>\n          </div>\n        </div>\n\n      </div>\n    </div>\n  </section>\n\n  <!-- ============ FOOTER ============ -->";
const pageScripts = [{"type":"","src":"","content":"// ===== FAQ accordion + search + scroll-spy =====\n  (function(){\n    const items   = document.querySelectorAll('[data-faq-item]');\n    const toggles = document.querySelectorAll('[data-faq-toggle]');\n    const cats    = document.querySelectorAll('[data-faq-cat]');\n    const search  = document.querySelector('[data-faq-search]');\n    const clear   = document.querySelector('[data-faq-clear]');\n    const empty   = document.querySelector('[data-faq-empty]');\n    const navLinks= document.querySelectorAll('[data-faq-jump]');\n\n    // Accordion toggle\n    toggles.forEach(btn => {\n      btn.addEventListener('click', () => {\n        const item = btn.closest('[data-faq-item]');\n        const open = item.classList.contains('is-open');\n        // close all in same category\n        const parent = item.closest('[data-faq-cat]');\n        parent.querySelectorAll('.faq-item.is-open').forEach(i => i.classList.remove('is-open'));\n        if (!open) item.classList.add('is-open');\n      });\n    });\n\n    // Search filter\n    function applyFilter(){\n      const q = (search.value || '').trim().toLowerCase();\n      let matches = 0;\n      items.forEach(item => {\n        const text = item.textContent.toLowerCase();\n        const hit = q === '' || text.includes(q);\n        item.classList.toggle('is-hidden', !hit);\n        if (hit) matches++;\n      });\n      // hide categories that have zero matches\n      cats.forEach(cat => {\n        const visible = cat.querySelectorAll('.faq-item:not(.is-hidden)').length;\n        cat.style.display = visible === 0 ? 'none' : '';\n      });\n      empty.classList.toggle('is-visible', matches === 0 && q !== '');\n      clear.classList.toggle('is-visible', q !== '');\n    }\n    search.addEventListener('input', applyFilter);\n    clear.addEventListener('click', () => { search.value = ''; applyFilter(); search.focus(); });\n\n    // Sidebar smooth scroll + active state\n    navLinks.forEach(link => {\n      link.addEventListener('click', e => {\n        e.preventDefault();\n        const id = link.dataset.faqJump;\n        const target = document.getElementById(id);\n        if (target){\n          const top = target.getBoundingClientRect().top + window.pageYOffset - 100;\n          window.scrollTo({ top, behavior: 'smooth' });\n        }\n      });\n    });\n\n    // Scroll spy\n    function updateActive(){\n      const scrollY = window.pageYOffset + 160;\n      let activeId = null;\n      cats.forEach(cat => {\n        if (cat.offsetTop <= scrollY) activeId = cat.id;\n      });\n      navLinks.forEach(link => {\n        link.classList.toggle('is-active', link.dataset.faqJump === activeId);\n      });\n    }\n    let scrollT;\n    window.addEventListener('scroll', () => {\n      clearTimeout(scrollT);\n      scrollT = setTimeout(updateActive, 50);\n    });\n    updateActive();\n  })();"}];

export default function FAQ() {
  return <ScopedPageContent pageCss={pageCss} pageHtml={pageHtml} pageScripts={pageScripts} />;
}
